function onlyDigits(value) {
  return String(value || '').replace(/\D/g, '');
}

function normalizePhone(value) {
  let digits = onlyDigits(value);
  if (!digits) return '';
  if (digits.startsWith('550')) digits = '55' + digits.slice(3);
  if (!digits.startsWith('55') && digits.length > 11) digits = digits.slice(0, 11);
  if (digits.length === 10 || digits.length === 11) digits = '55' + digits;
  if (digits.startsWith('55') && digits.length > 13) digits = digits.slice(0, 13);
  return digits;
}

function normalizeText(value) {
  return String(value || '').trim().replace(/\s+/g, ' ');
}

function matchKey(value) {
  return normalizeText(value)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

function unitKey(value) {
  return matchKey(value)
    .replace(/\b(apto|apartamento|apt|ap|bloco|bl|unidade|casa)\b/g, '')
    .replace(/[^a-z0-9]/g, '');
}

function pick(source, names) {
  for (const name of names) {
    const value = source?.[name];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return '';
}

function findMorador(moradores, nome, unidade) {
  const nomeBusca = matchKey(nome);
  const unidadeBusca = unitKey(unidade);

  if (nomeBusca && unidadeBusca) {
    const matchCompleto = moradores.find((row) => (
      matchKey(row.nome) === nomeBusca && unitKey(row.unidade) === unidadeBusca
    ));
    if (matchCompleto) return matchCompleto;
  }

  if (nomeBusca) {
    const matchNome = moradores.find((row) => matchKey(row.nome) === nomeBusca);
    if (matchNome) return matchNome;
  }

  if (unidadeBusca) {
    const matchUnidade = moradores.find((row) => unitKey(row.unidade) === unidadeBusca);
    if (matchUnidade) return matchUnidade;
  }

  return null;
}

const body = $('POST /recebai/encomendas').first().json.body || {};
const moradores = $input.all()
  .map((item) => item.json || {})
  .filter((row) => row.id && row.id !== 'id');

const id = normalizeText(pick(body, ['id'])) || 'enc_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
const trackingCode = normalizeText(pick(body, ['tracking_code', 'codigo_rastreio', 'codigo', 'rastreio', 'tracking']));
const destinatarioNome = normalizeText(pick(body, ['destinatario_nome', 'nome_destinatario', 'destinatario', 'morador_nome', 'nome']));
const destinatarioUnidade = normalizeText(pick(body, ['destinatario_unidade', 'unidade_destinatario', 'unidade', 'apto', 'apartamento', 'endereco']));
const transportadora = normalizeText(pick(body, ['transportadora', 'carrier', 'empresa'])) || 'Nao informado';
const errors = [];

if (!trackingCode) errors.push('tracking_code obrigatorio');
if (!destinatarioNome) errors.push('destinatario_nome obrigatorio');
if (!destinatarioUnidade) errors.push('destinatario_unidade obrigatorio');

if (errors.length) {
  throw new Error('Payload de encomenda invalido: ' + errors.join('; '));
}

const morador = findMorador(moradores, destinatarioNome, destinatarioUnidade);
const telefoneDoMorador = normalizePhone(morador?.celular);
const telefoneDoPayload = normalizePhone(pick(body, ['destinatario_telefone', 'telefone_destinatario', 'telefone', 'celular', 'whatsapp']));
const destinatarioTelefone = telefoneDoMorador || telefoneDoPayload;

const notificationText = destinatarioTelefone
  ? 'Ola ' + destinatarioNome + '! Sua encomenda (' + transportadora + ' - ' + trackingCode.toUpperCase() + ') chegou na portaria. Por favor, retire no horario disponivel.'
  : '';

return [{
  json: {
    id,
    tracking_code: trackingCode.toUpperCase(),
    destinatario_nome: destinatarioNome,
    destinatario_unidade: destinatarioUnidade,
    destinatario_telefone: destinatarioTelefone,
    transportadora,
    status: 'aguardando_retirada',
    created_at: new Date().toISOString(),
    retirada_at: '',
    retirada_por: '',
    notification_text: notificationText,
    morador_encontrado: Boolean(morador),
    morador_id: normalizeText(morador?.id)
  }
}];

const encomenda = $('Agente IA - Tratar JSON da Encomenda').first().json;

if (!encomenda.destinatario_telefone || !encomenda.notification_text) {
  return [];
}

return [{
  json: {
    number: encomenda.destinatario_telefone,
    text: encomenda.notification_text
  }
}];
